/**
 * Featured Extractor Module for ElevateLI
 * Handles extraction of LinkedIn profile featured section
 * This module will be concatenated into analyzer.js for Manifest V3 compatibility
 */

const FeaturedExtractor = {
  name: 'featured',
  
  selectors: [
    'section[data-section="featured"]',
    'section:has(h2:contains("Featured"))',
    'div[data-view-name="profile-card"]:has(h2:contains("Featured"))',
    'section.pv-profile-section:has(.pv-featured-container)',
    'section#featured-section'
  ],
  
  /**
   * Quick scan for featured section existence
   * @returns {Object} Scan results
   */
  async scan() {
    const startTime = Date.now();
    
    const section = BaseExtractor.findSection(this.selectors, 'Featured');
    const exists = !!section;
    
    let itemCount = 0;
    if (exists) {
      // Count featured items (posts, articles, media)
      const items = section.querySelectorAll('.pvs-list__paged-list-item, .artdeco-list__item, .pv-featured-container__item');
      itemCount = items.length;
    }
    
    return {
      exists,
      itemCount
    };
  },
  
  /**
   * Extract featured data for completeness scoring
   * @returns {Object} Basic featured data
   */
  async extract() {
    const startTime = Date.now();
    const scanResult = await this.scan();
    
    if (!scanResult.exists) {
      return {
        exists: false,
        count: 0,
        hasContent: false
      };
    }
    
    const result = {
      exists: true,
      count: scanResult.itemCount,
      hasContent: scanResult.itemCount > 0
    };
    
    return result;
  },
  
  /**
   * Deep extraction for AI analysis
   * @returns {Object} Detailed featured data
   */
  async extractDeep() {
    const startTime = Date.now();
    const basicData = await this.extract();
    
    if (!basicData.exists || basicData.count === 0) return basicData;
    
    const section = BaseExtractor.findSection(this.selectors, 'Featured');
    const featuredItems = await this.extractFeaturedItems(section);
    
    const result = {
      ...basicData,
      items: featuredItems,
      
      // Analysis features
      itemTypes: this.categorizeItems(featuredItems),
      hasExternalContent: featuredItems.some(item => item.isExternal),
      hasRecentContent: featuredItems.some(item => this.isRecent(item.date)),
      
      // For AI processing
      featuredSummary: this.summarizeFeatured(featuredItems)
    };
    
    return result;
  },
  
  /**
   * Extract featured items
   * @param {Element} section - Featured section
   * @returns {Array<Object>} Featured items
   */
  async extractFeaturedItems(section) {
    const items = [];
    const itemElements = section.querySelectorAll('.pvs-list__paged-list-item, .artdeco-list__item');
    
    for (const element of itemElements) {
      const item = await this.extractFeaturedItem(element);
      if (item.title || item.type) {
        items.push(item);
      }
    }
    
    return items;
  },
  
  /**
   * Extract single featured item
   * @param {Element} element - Featured item element
   * @returns {Object} Featured item data
   */
  async extractFeaturedItem(element) {
    const item = {
      title: '',
      type: 'unknown',
      description: '',
      url: '',
      date: '',
      isExternal: false
    };
    
    // Extract title
    const titleEl = element.querySelector('.t-bold span[aria-hidden="true"], h3 span[aria-hidden="true"]');
    item.title = BaseExtractor.extractTextContent(titleEl);
    
    // Extract type (post, article, media, etc.)
    const typeEl = element.querySelector('.t-12, .pv-featured-container__label');
    const typeText = BaseExtractor.extractTextContent(typeEl);
    item.type = this.determineItemType(typeText, item.title);
    
    // Extract description
    const descEl = element.querySelector('.t-14 span[aria-hidden="true"]');
    item.description = BaseExtractor.extractTextContent(descEl);
    
    // Extract URL
    const linkEl = element.querySelector('a[href]');
    if (linkEl) {
      item.url = linkEl.href;
      item.isExternal = !item.url.includes('linkedin.com');
    }
    
    // Extract date if available
    const dateEl = element.querySelector('.t-black--light');
    item.date = BaseExtractor.extractTextContent(dateEl);
    
    return item;
  },
  
  /**
   * Determine item type
   * @param {string} typeText - Type text from element
   * @param {string} title - Item title
   * @returns {string} Item type
   */
  determineItemType(typeText, title) {
    const text = (typeText + ' ' + title).toLowerCase();
    
    if (text.includes('post')) return 'post';
    if (text.includes('article')) return 'article';
    if (text.includes('video')) return 'video';
    if (text.includes('document')) return 'document';
    if (text.includes('link')) return 'link';
    if (text.includes('media')) return 'media';
    
    return 'other';
  },
  
  /**
   * Categorize featured items
   * @param {Array<Object>} items - Featured items
   * @returns {Object} Item types with counts
   */
  categorizeItems(items) {
    const types = {};
    
    items.forEach(item => {
      types[item.type] = (types[item.type] || 0) + 1;
    });
    
    return types;
  },
  
  /**
   * Check if item is recent
   * @param {string} dateStr - Date string
   * @returns {boolean}
   */
  isRecent(dateStr) {
    if (!dateStr) return false;
    
    // Simple check for recent keywords
    const recentIndicators = /today|yesterday|day ago|week ago|month ago/i;
    return recentIndicators.test(dateStr);
  },
  
  /**
   * Summarize featured items for AI
   * @param {Array<Object>} items - Featured items
   * @returns {string} Summary
   */
  summarizeFeatured(items) {
    if (items.length === 0) return 'No featured content';
    
    const typeGroups = {};
    items.forEach(item => {
      if (!typeGroups[item.type]) {
        typeGroups[item.type] = [];
      }
      typeGroups[item.type].push(item.title || 'Untitled');
    });
    
    const parts = [];
    Object.entries(typeGroups).forEach(([type, titles]) => {
      parts.push(`${type}s: ${titles.length} items`);
    });
    
    return parts.join(', ');
  }
};


  /* ============================================
   * MODULE: scoring/completeness-scorer.js
   * ============================================ */
/**
 * Completeness Scorer Module for ElevateLI
 * Calculates profile completeness score based on section data
 * This module will be concatenated into analyzer.js for Manifest V3 compatibility
 */

class ProfileCompletenessCalculator {
  constructor() {
    // Section weights (total = 100)
    this.weights = {
      photo: 5,
      headline: 10,
      about: 20,
      experience: 25,
      skills: 15,
      education: 10,
      recommendations: 10,
      certifications: 3,
      projects: 2
    };
    
    // LinkedIn character limits (2025)
    this.characterLimits = {
      headline: 220,
      about: 2600,
      experienceDescription: 2000
    };
    
    // Content depth thresholds
    this.contentDepthThresholds = {
      headline: {
        excellent: 0.75,  // 165+ chars
        good: 0.50,       // 110+ chars
        minimum: 0.30     // 66+ chars
      },
      about: {
        excellent: 0.60,  // 1560+ chars
        good: 0.40,       // 1040+ chars
        minimum: 0.20     // 520+ chars
      },
      experienceDescription: {
        excellent: 0.40,  // 800+ chars
        good: 0.25,       // 500+ chars
        minimum: 0.15     // 300+ chars
      }
    };
    
    // Section-specific rules
    this.rules = {
      photo: {
        check: (data) => data.exists || data === true,
        points: 5,
        getMessage: () => "Add a professional photo"
      },
      
      headline: {
        check: (data) => data && data.charCount >= 50,
        getScore: function(data) {
          if (!data || !data.exists || !data.charCount) return 0;
          const utilization = data.charCount / this.characterLimits.headline;
          
          if (utilization >= this.contentDepthThresholds.headline.excellent) return 1.0;
          if (utilization >= this.contentDepthThresholds.headline.good) return 0.8;
          if (utilization >= this.contentDepthThresholds.headline.minimum) return 0.5;
          return 0.2;
        },
        points: 10,
        getMessage: function(data) {
          if (!data || !data.exists) return "Add a professional headline";
          const headlineLimit = 220; // LinkedIn headline character limit
          const utilization = data.charCount / headlineLimit;
          if (utilization < 0.30) return `Expand headline to 70+ characters (currently ${data.charCount}/220)`;
          if (utilization < 0.50) return `Add more detail to headline (aim for 110+ characters)`;
          if (utilization < 0.75) return `Optimize headline further (165+ characters recommended)`;
          return "Headline looks good - ensure keywords are included";
        }
      },
      
      about: {
        check: (data) => {
          // Must have actual content, not just the section existing
          return data && data.exists && data.charCount >= 800;
        },
        getScore: function(data) {
          if (!data || !data.exists || !data.charCount) return 0;
          const utilization = data.charCount / this.characterLimits.about;
          
          if (utilization >= this.contentDepthThresholds.about.excellent) return 1.0;
          if (utilization >= this.contentDepthThresholds.about.good) return 0.75;
          if (utilization >= this.contentDepthThresholds.about.minimum) return 0.4;
          if (utilization >= 0.1) return 0.2;
          return 0;
        },
        points: 20,
        getMessage: function(data) {
          if (!data || !data.exists || data.charCount === 0) return "Add an About section";
          const aboutLimit = 2600; // LinkedIn about section character limit
          const utilization = data.charCount / aboutLimit;
          if (utilization < 0.20) return `About section too brief (${data.charCount}/2600) - aim for 1000+ characters`;
          if (utilization < 0.40) return `Expand About section (${data.charCount}/2600) - recruiters need more detail`;
          if (utilization < 0.60) return `Good About section - consider adding more achievements`;
          return "Excellent About section depth";
        }
      },
      
      experience: {
        check: (data) => {
          if (!data || !data.exists || data.count === 0) return false;
          if (data.count < 2) return false;
          if (!data.hasCurrentRole) return false;
          // Check average description length (aim for 150+ chars per role)
          // Only check if we have the data
          if (data.averageDescriptionLength !== undefined) {
            return data.averageDescriptionLength >= 150;
          }
          // Fallback - if we have 2+ roles and current role, consider it complete
          return true;
        },
        getScore: function(data) {
          if (!data || !data.exists || data.count === 0) return 0;
          
          // Base scoring components
          const hasRoles = data.count >= 2 ? 0.3 : (data.count === 1 ? 0.15 : 0);
          const hasCurrent = data.hasCurrentRole ? 0.2 : 0;
          
          // Content depth scoring
          let contentScore = 0;
          if (data.averageDescriptionLength !== undefined) {
            const avgUtilization = data.averageDescriptionLength / this.characterLimits.experienceDescription;
            if (avgUtilization >= this.contentDepthThresholds.experienceDescription.excellent) {
              contentScore = 0.3;
            } else if (avgUtilization >= this.contentDepthThresholds.experienceDescription.good) {
              contentScore = 0.2;
            } else if (avgUtilization >= this.contentDepthThresholds.experienceDescription.minimum) {
              contentScore = 0.1;
            }
          }
          
          // Recency bonus - recent roles get more weight
          let recencyScore = 0.2; // Default if has current role
          if (data.hasCurrentRole) {
            recencyScore = 0.2;
          } else if (data.recentRolesCount !== undefined && data.count > 0) {
            const recencyRatio = data.recentRolesCount / data.count;
            recencyScore = recencyRatio * 0.2;
          }
          
          const score = hasRoles + hasCurrent + contentScore + recencyScore;
          return Math.min(score, 1.0);
        },
        points: 25,
        getMessage: function(data) {
          if (!data || !data.exists || data.count === 0) return "Add your work experience";
          if (data.count === 1) return "Add more work experiences (at least 2)";
          if (!data.hasCurrentRole) return "Update with your current position";
          if (data.averageDescriptionLength !== undefined && data.averageDescriptionLength < 300) {
            return `Expand experience descriptions (avg ${Math.round(data.averageDescriptionLength)} chars) - aim for 500+ per role`;
          }
          return "Enhance experience descriptions";
        }
      },
      
      skills: {
        check: (data) => data && data.count >= 10,
        points: 15,
        getMessage: function(data) {
          if (!data || !data.exists || data.count === 0) return "Add relevant skills";
          if (data.count < 5) return "Add more skills (aim for 10+)";
          if (data.count < 10) return `Add ${10 - data.count} more skills`;
          return "Optimize your skills section";
        }
      },
      
      education: {
        check: (data) => data && data.count >= 1,
        points: 10,
        getMessage: function(data) {
          if (!data || !data.exists || data.count === 0) return "Add your education";
          return "Complete your education details";
        }
      },
      
      recommendations: {
        check: (data) => {
          if (!data || !data.exists || data.count === 0) return false;
          // Check if has recent recommendations (within 2 years)
          // Fallback to basic count check if recency data not available
          if (data.isCurrentlyEndorsed !== undefined || data.hasRecentRecommendations !== undefined) {
            return data.isCurrentlyEndorsed === true || data.hasRecentRecommendations === true;
          }
          // If no recency data, just check if has any recommendations
          return data.count >= 1;
        },
        points: 10,
        getMessage: function(data) {
          if (!data || !data.exists || data.count === 0) return "Request at least one recommendation";
          // Only show recency message if we actually have the data to check
          if ((data.isCurrentlyEndorsed === false || data.hasRecentRecommendations === false) &&
              (data.isCurrentlyEndorsed !== undefined || data.hasRecentRecommendations !== undefined)) {
            return "Request a recent recommendation (within 2 years)";
          }
          if (data.count < 3) return "Request more recommendations (aim for 3+)";
          return "Keep recommendations current";
        }
      },
      
      certifications: {
        check: (data) => data && data.count >= 1,
        points: 3,
        getMessage: () => "Add relevant certifications"
      },
      
      projects: {
        check: (data) => data && data.count >= 1,
        points: 2,
        getMessage: () => "Showcase projects you've worked on"
      }
    };
  }
  
  /**
   * Calculate completeness for all sections
   * @param {Object} sectionData - Data for all sections
   * @returns {Object} Complete scoring result
   */
  calculate(sectionData) {
    const startTime = Date.now();
    
    // Debug: Log what data we're starting with
    
    // Debug: Log the rules and weights
    
    const breakdown = {};
    const recommendations = [];
    let earnedPoints = 0;
    let totalPoints = 0;
    
    // Process each section
    for (const [section, weight] of Object.entries(this.weights)) {
      const data = sectionData[section];
      const rule = this.rules[section];
      
      // Debug: Log each section processing
      
      totalPoints += weight;
      
      if (rule && data !== undefined) {
        try {
          // Use getScore if available for graduated scoring, otherwise fall back to check
          const scoreMultiplier = rule.getScore ? rule.getScore.call(this, data) : (rule.check(data) ? 1 : 0);
          
          const points = weight * scoreMultiplier;
          earnedPoints += points;
          const passed = scoreMultiplier >= 0.5; // Consider >= 50% as "passed"
          
          // Debug logging for problem sections
          if (section === 'about' || section === 'experience' || section === 'headline') {
          }
          
          breakdown[section] = {
            weight,
            earned: points,
            passed,
            scoreMultiplier,
            data: this.summarizeData(data)
          };
          
          if (scoreMultiplier < 1) {
            recommendations.push({
              section,
              priority: this.getPriority(section, weight, scoreMultiplier),
              message: rule.getMessage.call(this, data),
              impact: weight * (1 - scoreMultiplier),
              weight: weight,
              currentScore: scoreMultiplier
            });
          }
        } catch (error) {
          // Set default values for this section
          breakdown[section] = {
            weight,
            earned: 0,
            passed: false,
            scoreMultiplier: 0,
            data: null
          };
          // Continue processing other sections
        }
      } else {
        // Section not found or no rule
        breakdown[section] = {
          weight,
          earned: 0,
          passed: false,
          data: null
        };
        
        recommendations.push({
          section,
          priority: 'high',
          message: `Add ${section} section`,
          impact: weight,
          weight: weight
        });
      }
    }
    
    // Sort recommendations by impact
    recommendations.sort((a, b) => b.impact - a.impact);
    
    const percentage = Math.round((earnedPoints / totalPoints) * 100);
    
    // Debug: Log final calculation
    
    Logger.info(`[ProfileCompletenessCalculator] Calculated in ${Date.now() - startTime}ms`);
    
    return {
      score: percentage,
      earnedPoints,
      totalPoints,
      breakdown,
      recommendations: recommendations.slice(0, 5), // Top 5 recommendations
      allRecommendations: recommendations,
      isOptimized: percentage >= 85,
      level: this.getLevel(percentage)
    };
  }
  
  /**
   * Calculate section-specific completeness
   * @param {string} section - Section name
   * @param {Object} data - Section data
   * @returns {Object} Section score
   */
  scoreSection(section, data) {
    const weight = this.weights[section];
    const rule = this.rules[section];
    
    if (!weight || !rule) {
      return {
        score: 0,
        maxScore: 0,
        percentage: 0,
        passed: false
      };
    }
    
    const passed = rule.check(data);
    const score = passed ? weight : 0;
    
    return {
      score,
      maxScore: weight,
      percentage: passed ? 100 : 0,
      passed,
      recommendation: !passed ? rule.getMessage(data) : null
    };
  }
  
  /**
   * Get priority level for a section
   * @param {string} section - Section name
   * @param {number} weight - Section weight
   * @returns {string} Priority level
   */
  getPriority(section, weight, scoreMultiplier = 0) {
    // Factor in both weight and how much improvement is needed
    const potentialGain = weight * (1 - scoreMultiplier);
    
    if (potentialGain >= 15) return 'critical';
    if (potentialGain >= 8) return 'high';
    if (potentialGain >= 4) return 'medium';
    return 'low';
  }
  
  /**
   * Get completeness level
   * @param {number} percentage - Completeness percentage
   * @returns {string} Level name
   */
  getLevel(percentage) {
    if (percentage >= 90) return 'excellent';
    if (percentage >= 75) return 'good';
    if (percentage >= 60) return 'fair';
    if (percentage >= 40) return 'needs_work';
    return 'poor';
  }
  
  /**
   * Summarize section data for storage
   * @param {Object} data - Section data
   * @returns {Object} Summary
   */
  summarizeData(data) {
    if (!data) return null;
    
    return {
      exists: data.exists || false,
      count: data.count || 0,
      charCount: data.charCount || 0,
      hasContent: data && (data.exists || data.count > 0 || data.charCount > 0)
    };
  }
  
  /**
   * Generate rich feedback for a section (used when completeness < 75%)
   * NOTE: Currently unused - planned for future enhancement
   * @deprecated Consider removing if not used by v1.1.0
   * @param {string} section - Section name
   * @param {Object} data - Section data
   * @returns {Object} Rich feedback with positive and improvements
   */
  generateRichFeedback(section, data) {
    const feedback = {
      positive: '',
      improvements: []
    };
    
    // Headline feedback
    if (section === 'headline' && data) {
      const util = data.charCount / this.characterLimits.headline;
      if (util >= 0.5) {
        feedback.positive = `Good headline foundation (${data.charCount} characters)`;
      } else if (util >= 0.3) {
        feedback.positive = `Headline present (${data.charCount} characters)`;
      }
      
      if (util < 0.75) {
        feedback.improvements.push({
          action: `Expand to ${Math.round(this.characterLimits.headline * 0.75)}+ characters`,
          rationale: 'Improves search visibility'
        });
      }
    }
    
    // About section feedback
    if (section === 'about' && data) {
      const util = data.charCount / this.characterLimits.about;
      if (util >= 0.4) {
        feedback.positive = `Strong About section with ${data.charCount} characters`;
      } else if (util >= 0.2) {
        feedback.positive = `About section started (${data.charCount} characters)`;
      }
      
      if (util < 0.4) {
        feedback.improvements.push({
          action: `Expand to 1000+ characters`,
          rationale: 'Recruiters spend more time on detailed profiles'
        });
      }
      
      if (data.charCount > 0 && data.charCount < 275) {
        feedback.improvements.push({
          action: `Ensure first 275 characters capture attention`,
          rationale: 'This appears before "See More" button'
        });
      }
    }
    
    // Experience feedback  
    if (section === 'experience' && data) {
      if (data.count >= 2 && data.hasCurrentRole) {
        feedback.positive = `${data.count} experiences with current role`;
      } else if (data.count >= 1) {
        feedback.positive = `${data.count} experience${data.count > 1 ? 's' : ''} documented`;
      }
      
      if (data.averageDescriptionLength && data.averageDescriptionLength < 500) {
        feedback.improvements.push({
          action: `Expand descriptions to 500+ characters per role`,
          rationale: 'Add achievements and metrics'
        });
      }
      
      if (!data.hasCurrentRole) {
        feedback.improvements.push({
          action: `Add your current position`,
          rationale: 'Current roles weighted heavily in search'
        });
      }
    }
    
    // Skills feedback
    if (section === 'skills' && data) {
      if (data.count >= 10) {
        feedback.positive = `${data.count} skills listed`;
      } else if (data.count > 0) {
        feedback.positive = `${data.count} skills added`;
      }
      
      if (data.count < 10) {
        feedback.improvements.push({
          action: `Add ${10 - data.count} more relevant skills`,
          rationale: 'Improves keyword matching'
        });
      }
    }
    
    return feedback;
  }
  
  /**
   * Get actionable recommendations
   * @param {Object} scoringResult - Complete scoring result
   * @param {Object} settings - User settings
   * @returns {Array<Object>} Prioritized recommendations
   */
  getActionableRecommendations(scoringResult, settings = {}) {
    const { targetRole, seniorityLevel } = settings;
    const recommendations = [...scoringResult.allRecommendations];
    
    // Adjust priorities based on target role
    if (targetRole) {
      recommendations.forEach(rec => {
        // Boost skills for technical roles
        if (targetRole.includes('engineer') && rec.section === 'skills') {
          rec.priority = 'critical';
        }
        // Boost experience for senior roles
        if (seniorityLevel === 'senior' && rec.section === 'experience') {
          rec.priority = 'critical';
        }
      });
    }
    
    // Group by priority
    const grouped = {
      critical: [],
      high: [],
      medium: [],
      low: []
    };
    
    recommendations.forEach(rec => {
      grouped[rec.priority].push(rec);
    });
    
    // Return top recommendations from each priority level
    return [
      ...grouped.critical.slice(0, 2),
      ...grouped.high.slice(0, 2),
      ...grouped.medium.slice(0, 1)
    ];
  }
}


  /* ============================================
   * MODULE: scoring/quality-scorer.js
   * ============================================ */
/**
 * Quality Scorer Module for ElevateLI
 * Prepares data for AI analysis and processes AI responses
 * This module will be concatenated into analyzer.js for Manifest V3 compatibility
 */

const QualityScorer = {
  // Section weights for final score calculation
  weights: {
    photo: 0.05,      // 5%
    headline: 0.10,   // 10%
    about: 0.30,      // 30%
    experience: 0.30, // 30%
    skills: 0.15,     // 15%
    education: 0.05,  // 5%
    other: 0.05       // 5% (recommendations, certifications, projects)
  },
  
  /**
   * Prepare profile data for AI analysis
   * @param {Object} profileData - Extracted profile data
   * @param {Object} settings - User settings
   * @param {Object} completenessResult - Completeness scoring result
   * @returns {Object} Prepared data for AI
   */
  prepareForAI(profileData, settings, completenessResult) {
    Logger.info('[QualityScorer] Preparing data for AI analysis');
    
    const prepared = {
      // Meta information
      targetRole: settings.targetRole || 'general professional',
      seniorityLevel: settings.seniorityLevel || 'mid-level',
      customInstructions: settings.customInstructions || '',
      
      // Profile sections
      sections: {},
      
      // Completeness context
      completenessScore: completenessResult.score,
      missingElements: completenessResult.recommendations.map(r => r.message),
      
      // Analysis instructions
      analysisType: settings.batchAnalysis ? 'batch' : 'individual'
    };
    
    // Prepare each section
    if (profileData.headline) {
      prepared.sections.headline = this.prepareHeadline(profileData.headline);
    }
    
    if (profileData.about) {
      prepared.sections.about = this.prepareAbout(profileData.about);
    }
    
    if (profileData.experience) {
      prepared.sections.experience = this.prepareExperience(profileData.experience);
    }
    
    if (profileData.skills) {
      prepared.sections.skills = this.prepareSkills(profileData.skills);
    }
    
    if (profileData.education) {
      prepared.sections.education = this.prepareEducation(profileData.education);
    }
    
    // Other sections (lower weight)
    prepared.sections.other = this.prepareOtherSections(profileData);
    
    Logger.debug('[QualityScorer] Prepared sections:', Object.keys(prepared.sections));
    
    return prepared;
  },
  
  /**
   * Prepare headline section
   * @param {Object} headline - Headline data
   * @returns {Object} Prepared headline
   */
  prepareHeadline(headline) {
    return {
      text: headline.text || '',
      charCount: headline.charCount || 0,
      hasKeywords: headline.hasKeywords || false,
      isGeneric: headline.isGeneric || false,
      analysis: {
        wordCount: headline.wordCount || 0,
        hasPipe: headline.hasPipe || false,
        hasCompany: headline.hasCompany || false,
        hasValue: headline.hasValue || false
      }
    };
  },
  
  /**
   * Prepare about section
   * @param {Object} about - About data
   * @returns {Object} Prepared about
   */
  prepareAbout(about) {
    return {
      text: about.text || '',
      charCount: about.charCount || 0,
      wordCount: about.wordCount || 0,
      paragraphs: about.paragraphs || [],
      analysis: {
        hasCallToAction: about.hasCallToAction || false,
        keywords: (about.keywords || []).slice(0, 10),
        sentiment: about.sentiment || 'neutral',
        readabilityScore: about.readabilityScore || 0
      }
    };
  },
  
  /**
   * Prepare experience section
   * @param {Object} experience - Experience data
   * @returns {Object} Prepared experience
   */
  prepareExperience(experience) {
    const experiences = experience.experiences || experience.experienceChunks || [];
    
    return {
      count: experience.count || 0,
      hasCurrentRole: experience.hasCurrentRole || false,
      totalMonths: experience.totalMonths || 0,
      experiences: experiences.slice(0, 5).map(exp => ({
        title: exp.title || '',
        company: exp.company || '',
        duration: exp.duration || '',
        description: exp.description || '', // Send full description - no truncation
        hasQuantifiedAchievements: exp.hasQuantifiedAchievements || false,
        hasTechStack: exp.hasTechStack || false
      })),
      analysis: {
        averageTenure: experience.averageTenure || 0,
        careerProgression: experience.careerProgression || 'unknown',
        hasQuantifiedAchievements: experience.hasQuantifiedAchievements || false
      }
    };
  },
  
  /**
   * Prepare skills section
   * @param {Object} skills - Skills data
   * @returns {Object} Prepared skills
   */
  prepareSkills(skills) {
    return {
      count: skills.count || 0,
      topSkills: (skills.skills || []).slice(0, 20).map(s => ({
        name: s.name,
        endorsed: s.endorsementCount > 0
      })),
      analysis: {
        hasEndorsements: skills.hasEndorsements || false,
        technicalCount: skills.technicalSkills?.length || 0,
        softSkillsCount: skills.softSkills?.length || 0,
        categories: Object.keys(skills.skillsByCategory || {})
      }
    };
  },
  
  /**
   * Prepare education section
   * @param {Object} education - Education data
   * @returns {Object} Prepared education
   */
  prepareEducation(education) {
    return {
      count: education.count || 0,
      highestDegree: education.highestDegree || 'none',
      schools: (education.schools || []).slice(0, 3).map(school => ({
        name: school.school || school.name || '',
        degree: school.degree || '',
        field: school.field || ''
      }))
    };
  },
  
  /**
   * Prepare other sections
   * @param {Object} profileData - All profile data
   * @returns {Object} Other sections summary
   */
  prepareOtherSections(profileData) {
    const other = {
      hasRecommendations: false,
      recommendationCount: 0,
      hasCertifications: false,
      certificationCount: 0,
      hasProjects: false,
      projectCount: 0,
      hasFeatured: false
    };
    
    if (profileData.recommendations?.exists) {
      other.hasRecommendations = profileData.recommendations.count > 0;
      other.recommendationCount = profileData.recommendations.receivedCount || 0;
    }
    
    if (profileData.certifications?.exists) {
      other.hasCertifications = profileData.certifications.count > 0;
      other.certificationCount = profileData.certifications.count || 0;
    }
    
    if (profileData.projects?.exists) {
      other.hasProjects = profileData.projects.count > 0;
      other.projectCount = profileData.projects.count || 0;
    }
    
    if (profileData.featured?.exists) {
      other.hasFeatured = profileData.featured.hasContent || false;
    }
    
    return other;
  },
  
  /**
   * Process AI response into structured scoring
   * @param {Object} aiResponse - Response from AI
   * @param {Object} profileData - Original profile data
   * @returns {Object} Processed scores and recommendations
   */
  processAIResponse(aiResponse, profileData) {
    Logger.info('[QualityScorer] Processing AI response');
    
    try {
      // Parse section scores
      const sectionScores = this.parseSectionScores(aiResponse.sectionScores || {});
      
      // Calculate weighted overall score
      const overallScore = this.calculateOverallScore(sectionScores);
      
      // Parse recommendations
      const recommendations = this.parseRecommendations(aiResponse.recommendations || {});
      
      // Parse insights
      const insights = this.parseInsights(aiResponse.insights || {});
      
      // Determine score cap based on missing sections
      const scoreCap = this.determineScoreCap(profileData);
      
      // Apply score cap if necessary
      const finalScore = Math.min(overallScore, scoreCap);
      
      Logger.debug('[QualityScorer] Calculated scores:', {
        raw: overallScore,
        capped: finalScore,
        cap: scoreCap
      });
      
      return {
        contentScore: finalScore,
        sectionScores: sectionScores,
        recommendations: recommendations,
        insights: insights,
        scoreCap: scoreCap,
        analysis: {
          strengths: this.identifyStrengths(sectionScores),
          weaknesses: this.identifyWeaknesses(sectionScores),
          priority: this.prioritizeImprovements(sectionScores, profileData)
        }
      };
      
    } catch (error) {
      Logger.error('[QualityScorer] Error processing AI response:', error);
      
      return {
        contentScore: 5.0,
        error: 'Failed to process AI response',
        sectionScores: {},
        recommendations: {
          critical: ['Unable to analyze profile quality. Please try again.']
        }
      };
    }
  },
  
  /**
   * Parse section scores from AI response
   * @param {Object} scores - Raw section scores
   * @returns {Object} Normalized scores
   */
  parseSectionScores(scores) {
    const normalized = {};
    
    Object.entries(scores).forEach(([section, score]) => {
      // Ensure score is between 0 and 10
      normalized[section] = Math.max(0, Math.min(10, parseFloat(score) || 0));
    });
    
    return normalized;
  },
  
  /**
   * Calculate weighted overall score
   * @param {Object} sectionScores - Section scores
   * @returns {number} Overall score
   */
  calculateOverallScore(sectionScores) {
    let totalScore = 0;
    let totalWeight = 0;
    
    Object.entries(this.weights).forEach(([section, weight]) => {
      const score = sectionScores[section];
      if (score !== undefined) {
        totalScore += score * weight;
        totalWeight += weight;
      }
    });
    
    // Normalize if not all sections were scored
    if (totalWeight > 0 && totalWeight < 1) {
      totalScore = totalScore / totalWeight;
    }
    
    return Math.round(totalScore * 10) / 10; // Round to 1 decimal
  },
  
  /**
   * Determine score cap based on missing critical sections
   * @param {Object} profileData - Profile data
   * @returns {number} Maximum possible score
   */
  determineScoreCap(profileData) {
    let cap = 10;
    
    // Critical sections that cap the score when missing
    if (!profileData.about?.exists || profileData.about?.charCount < 100) {
      cap = Math.min(cap, 7); // No meaningful About = max 7/10
    }
    
    if (!profileData.experience?.exists || profileData.experience?.count === 0) {
      cap = Math.min(cap, 6); // No experience = max 6/10
    }
    
    if (!profileData.skills?.exists || profileData.skills?.count < 5) {
      cap = Math.min(cap, 8); // Few skills = max 8/10
    }
    
    if (!profileData.headline?.exists || profileData.headline?.charCount < 30) {
      cap = Math.min(cap, 8); // Poor headline = max 8/10
    }
    
    return cap;
  },
  
  /**
   * Parse recommendations from AI response
   * @param {Object} recommendations - Raw recommendations
   * @returns {Object} Structured recommendations
   */
  parseRecommendations(recommendations) {
    const structured = {
      critical: [],
      high: [],
      medium: [],
      low: []
    };
    
    // Handle different recommendation formats
    if (Array.isArray(recommendations)) {
      structured.high = recommendations.slice(0, 5);
    } else if (typeof recommendations === 'object') {
      Object.entries(recommendations).forEach(([priority, items]) => {
        if (structured[priority] && Array.isArray(items)) {
          structured[priority] = items;
        }
      });
    }
    
    return structured;
  },
  
  /**
   * Parse insights from AI response
   * @param {Object} insights - Raw insights
   * @returns {Object} Structured insights
   */
  parseInsights(insights) {
    return {
      strengths: insights.strengths || '',
      improvements: insights.improvements || '',
      industryAlignment: insights.industryAlignment || '',
      overallAssessment: insights.overallAssessment || ''
    };
  },
  
  /**
   * Identify profile strengths
   * @param {Object} sectionScores - Section scores
   * @returns {Array<string>} Strengths
   */
  identifyStrengths(sectionScores) {
    const strengths = [];
    
    Object.entries(sectionScores).forEach(([section, score]) => {
      if (score >= 8) {
        strengths.push(`Strong ${section} section (${score}/10)`);
      }
    });
    
    return strengths;
  },
  
  /**
   * Identify profile weaknesses
   * @param {Object} sectionScores - Section scores
   * @returns {Array<string>} Weaknesses
   */
  identifyWeaknesses(sectionScores) {
    const weaknesses = [];
    
    Object.entries(sectionScores).forEach(([section, score]) => {
      if (score < 6) {
        weaknesses.push(`Weak ${section} section (${score}/10)`);
      }
    });
    
    return weaknesses;
  },
  
  /**
   * Prioritize improvements based on scores and weights
   * @param {Object} sectionScores - Section scores
   * @param {Object} profileData - Profile data
   * @returns {Array<Object>} Prioritized improvements
   */
  prioritizeImprovements(sectionScores, profileData) {
    const improvements = [];
    
    Object.entries(this.weights).forEach(([section, weight]) => {
      const score = sectionScores[section] || 0;
      const potentialGain = (10 - score) * weight;
      
      if (score < 8) {
        improvements.push({
          section,
          currentScore: score,
          weight,
          potentialGain,
          priority: potentialGain > 1 ? 'high' : potentialGain > 0.5 ? 'medium' : 'low'
        });
      }
    });
    
    // Sort by potential gain
    improvements.sort((a, b) => b.potentialGain - a.potentialGain);
    
    return improvements;
  },
  
  /**
   * Truncate text to specified length
   * @param {string} text - Text to truncate
   * @param {number} maxLength - Maximum length
   * @returns {string} Truncated text
   */
  truncateText(text, maxLength) {
    if (text.length <= maxLength) return text;
    return text.substring(0, maxLength) + '...';
  },
  
  /**
   * Generate prompt for AI analysis
   * @param {Object} preparedData - Prepared profile data
   * @param {string} analysisType - Type of analysis
   * @returns {string} AI prompt
   */
  generatePrompt(preparedData, analysisType = 'comprehensive') {
    const prompts = {
      comprehensive: `Analyze this LinkedIn profile for a ${preparedData.targetRole} at ${preparedData.seniorityLevel} level. 
        Score each section from 0-10 based on clarity, impact, and relevance to the target role.
        Current completeness: ${preparedData.completenessScore}%.
        Missing elements: ${preparedData.missingElements.join(', ')}.
        
        Provide:
        1. Section scores (0-10) for: headline, about, experience, skills, education, other
        2. Critical recommendations (top 3 most impactful improvements)
        3. High priority recommendations (next 3-5 improvements)
        4. Brief insights on strengths and areas for improvement
        
        ${preparedData.customInstructions}`,
      
      quick: `Quick quality check for LinkedIn profile (${preparedData.targetRole}). 
        Rate overall content quality 0-10 and provide top 3 improvements.`,
      
      section: `Analyze this specific LinkedIn section and rate 0-10 for quality and impact.`
    };
    
    return prompts[analysisType] || prompts.comprehensive;
  }
};


  /* ============================================
   * MODULE: analysis/first-impression-analyzer.js
   * ============================================ */
/**
 * First Impression Analyzer Module for ElevateLI
 * Handles unified analysis of all first impression elements (headline, photo, banner, etc.)
 * [CRITICAL_PATH:FIRST_IMPRESSION_CORE] - P0: Unified first impression analysis
 */

const FirstImpressionAnalyzer = {
  // Configuration for all first impression elements
  elements: {
    headline: { 
      weight: 0.4, 
      required: true,
      extractor: 'headline',
      aiHandler: 'createHeadlinePrompt',
      description: 'Professional headline text'
    },
    photo: { 
      weight: 0.3, 
      required: false, 
      extractor: 'photo',
      description: 'Profile photo existence'
    },
    banner: { 
      weight: 0.2, 
      required: false, 
      extractor: 'banner',
      description: 'Background banner customization'
    },
    openToWork: { 
      weight: 0.1, 
      required: false,
      extractor: 'metadata',
      impact: 'Increases recruiter reach by 40%',
      description: 'Open to work badge visibility'
    }
  },
  
  /**
   * Build unified data package for first impression analysis
   * [CRITICAL_PATH:FIRST_IMPRESSION_DATA] - P0: Must include all visual elements
   */
  buildFirstImpressionData(extractedData) {
    const data = {
      headline: extractedData.headline?.text || '',
      headlineCharCount: extractedData.headline?.charCount || 0,
      photo: {
        exists: extractedData.photo?.exists || false,
        hasPhoto: extractedData.photo?.exists || false
      },
      banner: {
        exists: extractedData.banner?.exists || false,
        isCustomBanner: extractedData.banner?.isCustomBanner || false
      },
      metadata: {
        openToWork: extractedData.openToWork?.enabled || false,
        openToWorkDetails: extractedData.openToWork?.details || null,
        creatorMode: extractedData.creatorMode?.enabled || false,
        connectionCount: extractedData.connections?.count || 0,
        verified: extractedData.verified || false
      }
    };
    
    return data;
  },
  
  /**
   * Calculate unified score from individual element scores
   * [CRITICAL_PATH:UNIFIED_SCORING] - P0: Must properly weight all elements
   */
  calculateUnifiedScore(elementScores) {
    let totalWeight = 0;
    let weightedSum = 0;
    const scoreDetails = [];
    
    Object.entries(elementScores).forEach(([element, score]) => {
      if (score !== null && score !== undefined && this.elements[element]) {
        const config = this.elements[element];
        const weight = config.weight;
        
        weightedSum += score * weight;
        totalWeight += weight;
        
        scoreDetails.push({
          element,
          score,
          weight,
          contribution: score * weight
        });
      }
    });
    
    const finalScore = totalWeight > 0 ? Math.round(weightedSum / totalWeight) : null;
    
    return finalScore;
  },
  
  /**
   * Generate collated summary message based on scores
   */
  generateSummary(elementScores, improvements) {
    const hasPhoto = elementScores.photo !== null && elementScores.photo !== undefined;
    const hasCustomBanner = elementScores.banner !== null && elementScores.banner !== undefined;
    const headlineScore = elementScores.headline || 0;
    const photoScore = elementScores.photo || 0;
    
    // Calculate average of available elements
    const scores = Object.values(elementScores).filter(s => s !== null && s !== undefined);
    const avgScore = scores.length > 0 ? scores.reduce((a, b) => a + b, 0) / scores.length : 0;
    
    // Generate appropriate summary based on scores
    if (avgScore >= 8) {
      if (hasPhoto && hasCustomBanner) {
        return "Excellent first impression with professional headline, photo, and custom banner.";
      } else if (hasPhoto) {
        return "Strong professional presence with excellent headline and photo.";
      } else {
        return "Excellent headline that makes a strong first impression.";
      }
    } else if (avgScore >= 6) {
      if (hasPhoto && photoScore >= 4) {
        return "Good headline and photo with room for improvement.";
      } else if (hasPhoto) {
        return "Decent first impression but photo and headline need work.";
      } else {
        return "Good headline but missing profile photo limits your visibility.";
      }
    } else if (avgScore >= 4) {
      if (!hasPhoto) {
        return "Headline needs work and profile photo is missing.";
      } else {
        return "First impression needs significant improvement across headline and visuals.";
      }
    } else {
      return "Weak first impression - urgent improvements needed for headline and visuals.";
    }
  },
  
  /**
   * Merge improvements from different elements into unified list
   */
  mergeImprovements(elementResults) {
    const improvements = [];
    
    // Process each element's improvements
    Object.entries(elementResults).forEach(([element, result]) => {
      if (result && result.improvements) {
        result.improvements.forEach(imp => {
          improvements.push({
            ...imp,
            source: element,
            sourceLabel: this.elements[element]?.description || element
          });
        });
      }
    });
    
    // Sort by priority and limit
    improvements.sort((a, b) => {
      const priorityOrder = { high: 0, medium: 1, low: 2 };
      return (priorityOrder[a.priority] || 2) - (priorityOrder[b.priority] || 2);
    });
    
    return improvements.slice(0, 5); // Max 5 improvements
  },
  
  /**
   * Check if an element should be analyzed
   */
  shouldAnalyzeElement(element, data, hasVisionAI) {
    const config = this.elements[element];
    
    if (!config) return false;
    
    // Vision AI no longer used
    
    // Check if element exists
    switch (element) {
      case 'headline':
        return !!data.headline;
      case 'photo':
        return data.photo?.exists || !data.photo?.exists; // Analyze if missing too
      case 'banner':
        return data.banner?.isCustomBanner; // Only analyze custom banners
      case 'openToWork':
        return true; // Always check this metadata
      default:
        return false;
    }
  },
  
  /**
   * Get missing elements that impact first impression
   */
  getMissingElements(data) {
    const missing = [];
    
    if (!data.photo?.exists) {
      missing.push({
        element: 'photo',
        message: 'Add a professional photo',
        impact: 'Profiles with photos get 21x more views',
        priority: 'high'
      });
    }
    
    if (!data.banner?.isCustomBanner) {
      missing.push({
        element: 'banner',
        message: 'Add a custom background banner',
        impact: 'Showcase your brand and stand out',
        priority: 'medium'
      });
    }
    
    if (!data.metadata?.openToWork && data.metadata?.openToWork !== undefined) {
      missing.push({
        element: 'openToWork',
        message: 'Consider enabling "Open to Work" badge',
        impact: 'Increases recruiter visibility by 40%',
        priority: 'medium'
      });
    }
    
    return missing;
  }
};

// Export for use in analyzer
if (typeof module !== 'undefined' && module.exports) {
  module.exports = FirstImpressionAnalyzer;
}


